import xml.etree.ElementTree as ET
from defusedxml import ElementTree as DefusedET
from typing import Dict, Any, Union
import os


def parse_xml_config(xml_source: str) -> Dict[str, Any]:
    """
    Parse an XML configuration file and return settings as a dictionary.
    
    Uses defusedxml to safely parse untrusted XML, preventing:
    - XML External Entity (XXE) attacks
    - XML Entity Expansion (Billion Laughs) attacks
    - DTD retrieval from external sources
    
    Args:
        xml_source: Path to an XML file or an XML string.
        
    Returns:
        A dictionary containing the parsed configuration settings.
        
    Raises:
        FileNotFoundError: If the specified file path does not exist.
        DefusedET.DTDForbidden: If the XML contains a DTD.
        DefusedET.EntitiesForbidden: If the XML contains entity definitions.
        DefusedET.ExternalReferenceForbidden: If the XML contains external references.
        ET.ParseError: If the XML is malformed.
    """
    if os.path.isfile(xml_source):
        tree = DefusedET.parse(xml_source)
        root = tree.getroot()
    else:
        root = DefusedET.fromstring(xml_source)
    
    return _element_to_dict(root)


def _element_to_dict(element: ET.Element) -> Union[Dict[str, Any], str]:
    """
    Recursively convert an XML element and its children into a dictionary.
    
    Handles:
    - Element attributes (stored under '@attributes' key)
    - Text content (stored under '#text' key when mixed with children)
    - Repeated child elements (collected into lists)
    - Nested elements (recursively converted)
    - Leaf elements with only text content (stored as simple strings)
    
    Args:
        element: An XML Element to convert.
        
    Returns:
        A dictionary representation of the element, or a string if the
        element is a simple leaf node with only text content.
    """
    result = {}
    
    # Add attributes if present
    if element.attrib:
        result['@attributes'] = dict(element.attrib)
    
    # Process child elements
    children = list(element)
    
    if children:
        child_dict: Dict[str, Any] = {}
        
        for child in children:
            child_tag = child.tag
            child_value = _element_to_dict(child)
            
            if child_tag in child_dict:
                # Convert to list if we encounter duplicate tags
                existing = child_dict[child_tag]
                if isinstance(existing, list):
                    existing.append(child_value)
                else:
                    child_dict[child_tag] = [existing, child_value]
            else:
                child_dict[child_tag] = child_value
        
        result.update(child_dict)
        
        # Add text content if present alongside children
        text = element.text
        if text and text.strip():
            result['#text'] = text.strip()
    else:
        # Leaf element with text content only
        text = element.text
        text_value = text.strip() if text and text.strip() else ''
        
        if not result:
            # No attributes, just return the text value
            return text_value
        else:
            # Has attributes, include text in the dict
            if text_value:
                result['#text'] = text_value
    
    return result


def parse_xml_config_flat(xml_source: str, separator: str = '.') -> Dict[str, str]:
    """
    Parse an XML configuration file and return settings as a flat dictionary
    with dot-separated keys for nested elements.
    
    Args:
        xml_source: Path to an XML file or an XML string.
        separator: Separator for nested key names (default: '.').
        
    Returns:
        A flat dictionary with dot-separated keys and string values.
    """
    nested = parse_xml_config(xml_source)
    flat: Dict[str, str] = {}
    _flatten_dict(nested, flat, prefix='', separator=separator)
    return flat


def _flatten_dict(
    data: Any,
    result: Dict[str, str],
    prefix: str,
    separator: str
) -> None:
    """Recursively flatten a nested dictionary into dot-separated keys."""
    if isinstance(data, dict):
        for key, value in data.items():
            new_key = f"{prefix}{separator}{key}" if prefix else key
            _flatten_dict(value, result, new_key, separator)
    elif isinstance(data, list):
        for index, item in enumerate(data):
            new_key = f"{prefix}[{index}]"
            _flatten_dict(item, result, new_key, separator)
    else:
        result[prefix] = str(data)


